import { useState } from "react";
import { SIDEBAR_FILTER_OPTIONS, isSidebarOptionActive } from "../utils/productFilters";
import { useLang } from "../context/LangContext";

export default function Sidebar({ searchParams, setSearchParams }) {
  const [co, setCo] = useState(true);
  const [po, setPo] = useState(true);
  const [ro, setRo] = useState(true);
  const { t } = useLang();

  const applyOption = (opt) => {
    const p = opt.params || {};
    if (!p.view && !p.category) {
      setSearchParams({}, { replace: true });
      return;
    }
    const next = {};
    if (p.view) next.view = p.view;
    if (p.category) next.category = p.category;
    setSearchParams(next, { replace: true });
  };

  return (
    <div style={{ minWidth: 210, maxWidth: 220 }} className="sb-col">
      <div className="sb-section">
        <div className="sb-title" onClick={() => setCo(!co)}>
          {t.cats}
          <span>{co ? "▾" : "▸"}</span>
        </div>
        {co &&
          SIDEBAR_FILTER_OPTIONS.map((opt) => {
            const active = isSidebarOptionActive(opt, searchParams);
            return (
              <div
                key={opt.label}
                className="sb-item"
                onClick={() => applyOption(opt)}
                style={{ color: active ? "#D6247F" : "#666", fontWeight: active ? 700 : 400 }}
              >
                <input type="checkbox" checked={active} onChange={() => applyOption(opt)} readOnly />
                {opt.label}
              </div>
            );
          })}
      </div>
      <div className="sb-section">
        <div className="sb-title" onClick={() => setPo(!po)}>
          {t.price}
          <span>{po ? "▾" : "▸"}</span>
        </div>
        {po &&
          ["Moins de 1 500 DA", "1 500 – 2 500 DA", "2 500 – 3 500 DA", "Plus de 3 500 DA"].map((l) => (
            <div key={l} className="sb-item">
              <input type="checkbox" readOnly />
              {l}
            </div>
          ))}
      </div>
      <div className="sb-section">
        <div className="sb-title" onClick={() => setRo(!ro)}>
          {t.rating}
          <span>{ro ? "▾" : "▸"}</span>
        </div>
        {ro &&
          [4, 3, 2].map((r) => (
            <div key={r} className="sb-item">
              <input type="checkbox" readOnly />
              <span className="stars" style={{ fontSize: 11 }}>
                {"★".repeat(r)}
                {"☆".repeat(5 - r)}
              </span>
              <span style={{ fontSize: 11, color: "#AAA" }}>&amp; plus</span>
            </div>
          ))}
      </div>
      <div className="sb-section">
        <div className="sb-title">{t.onSale}</div>
        <div className="sb-item">
          <input type="checkbox" readOnly />
          Articles en solde
        </div>
      </div>
    </div>
  );
}
